#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, V1, V2;
        scanf("%d %d %d", &N, &V1, &V2);
        double tStairs = N * sqrt(2) / (double)V1;
        double tElevator = 2 * N / (double)V2;
        if (tStairs < tElevator) {
            printf("Stairs\n");
        } else {
            printf("Elevator\n");
        }
    }
    return 0;
}

